import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Student {
  name: string;
  studentNumber: string;
}

export interface TaskAttempt {
  index: number;
  target: string;
  firstTryCorrect: boolean;
  attempts: number;
  errors: number;
  skipped: boolean;
  typedHistory: string[];
}

export interface SessionSummary {
  startTimestampISO: string;
  endTimestampISO: string;
  totalErrors: number;
  totalSkipped: number;
  correctOnFirstTryCount: number;
  totalAttempts: number;
}

export enum GameState {
  LOGIN = 'LOGIN',
  PLAYING = 'PLAYING',
  RESULTS = 'RESULTS'
}

export interface Task {
  character: string;
  hint: string;
}

import { Task } from '../types';

const LETTERS = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ".split("");
const NUMBERS = "0123456789".split("");
const SHIFT_SYMBOLS = "!@#$%^&*(".split("");
const PUNCTUATION = "{[]};:'\"\\|,. < >/?`~_-+=".split("").filter(c => c !== " "); // Fixed punctuation list

const getHint = (char: string): string => {
  if (/[a-z]/.test(char)) return "Kleine letter.";
  if (/[A-Z]/.test(char)) return "Hoofdletter (gebruik Shift of Caps Lock).";
  if (/[0-9]/.test(char)) return "Cijfertoets.";
  if (SHIFT_SYMBOLS.includes(char)) return `Shift + ${"123456789".charAt(SHIFT_SYMBOLS.indexOf(char))}`;

  const mappings: Record<string, string> = {
    '[': 'Linker vierkant haakje.',
    ']': 'Rechter vierkant haakje.',
    '{': 'Shift + [',
    '}': 'Shift + ]',
    ';': 'Puntkomma toets.',
    ':': 'Shift + ;',
    "'": 'Aanhalingsteken toets.',
    '"': "Shift + '",
    '\\': 'Backslash toets.',
    '|': 'Shift + \\',
    ',': 'Komma toets.',
    '<': 'Shift + ,',
    '.': 'Punt toets.',
    '>': 'Shift + .',
    '/': 'Slash toets.',
    '?': 'Shift + /',
    '`': 'Backtick toets.',
    '~': 'Shift + `',
    '-': 'Minteken toets.',
    '_': 'Shift + -',
    '=': 'Is-gelijk toets.',
    '+': 'Shift + ='
  };

  return mappings[char] || "Speciaal teken.";
};

export const generateTasks = (): Task[] => {
  const tasks: Task[] = [];
  const charCounts: Record<string, number> = {};

  const getRandomFrom = (pool: string[]): string => {
    let char = pool[Math.floor(Math.random() * pool.length)];
    // Ensure max 2 repetitions
    let safety = 0;
    while (charCounts[char] >= 2 && safety < 100) {
      char = pool[Math.floor(Math.random() * pool.length)];
      safety++;
    }
    charCounts[char] = (charCounts[char] || 0) + 1;
    return char;
  };

  // 1-5: Letters only
  for (let i = 0; i < 5; i++) {
    const char = getRandomFrom(LETTERS);
    tasks.push({ character: char, hint: getHint(char) });
  }

  // 6-30: Mixed
  const mixedPool = [...LETTERS, ...NUMBERS, ...SHIFT_SYMBOLS, ...PUNCTUATION];
  for (let i = 5; i < 30; i++) {
    const char = getRandomFrom(mixedPool);
    tasks.push({ character: char, hint: getHint(char) });
  }

  return tasks;
};

import { jsPDF } from 'jspdf';
import { Student, TaskAttempt, SessionSummary } from '../types';

export const exportResultsToPdf = (
  student: Student,
  summary: SessionSummary,
  attempts: TaskAttempt[]
) => {
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.getWidth();
  let yPos = 20;

  // Title
  doc.setFontSize(22);
  doc.text('Type Trainer – Resultaat', pageWidth / 2, yPos, { align: 'center' });
  yPos += 15;

  // Student Info
  doc.setFontSize(12);
  doc.text(`Naam: ${student.name}`, 20, yPos);
  yPos += 7;
  doc.text(`Studentnummer: ${student.studentNumber}`, 20, yPos);
  yPos += 10;

  // Timestamps
  const start = new Date(summary.startTimestampISO).toLocaleString();
  const end = new Date(summary.endTimestampISO).toLocaleString();
  doc.text(`Start: ${start}`, 20, yPos);
  yPos += 7;
  doc.text(`Eind: ${end}`, 20, yPos);
  yPos += 15;

  // Summary
  doc.setFontSize(14);
  doc.text('Samenvatting', 20, yPos);
  yPos += 8;
  doc.setFontSize(12);
  doc.text(`Correct in 1e poging: ${summary.correctOnFirstTryCount} / 30`, 25, yPos);
  yPos += 7;
  doc.text(`Totaal fouten: ${summary.totalErrors}`, 25, yPos);
  yPos += 7;
  doc.text(`Totaal overgeslagen: ${summary.totalSkipped}`, 25, yPos);
  yPos += 15;

  // Table Header
  doc.setFontSize(14);
  doc.text('Gedetailleerde Resultaten', 20, yPos);
  yPos += 10;

  doc.setFontSize(10);
  const headers = ['Nr', 'Target', '1e keer goed?', 'Pogingen', 'Skipped'];
  const colWidths = [15, 25, 40, 30, 30];
  const startX = 20;

  // Draw Header
  let currentX = startX;
  headers.forEach((h, i) => {
    doc.text(h, currentX, yPos);
    currentX += colWidths[i];
  });
  yPos += 5;
  doc.line(20, yPos, pageWidth - 20, yPos);
  yPos += 7;

  // Table Rows
  attempts.forEach((attempt, index) => {
    // Check page break
    if (yPos > 270) {
      doc.addPage();
      yPos = 20;
      // Re-draw header on new page
      currentX = startX;
      headers.forEach((h, i) => {
        doc.text(h, currentX, yPos);
        currentX += colWidths[i];
      });
      yPos += 5;
      doc.line(20, yPos, pageWidth - 20, yPos);
      yPos += 7;
    }

    currentX = startX;
    doc.text(`${attempt.index}`, currentX, yPos);
    currentX += colWidths[0];
    doc.text(`'${attempt.target}'`, currentX, yPos);
    currentX += colWidths[1];
    doc.text(attempt.firstTryCorrect ? 'Ja' : 'Nee', currentX, yPos);
    currentX += colWidths[2];
    doc.text(`${attempt.attempts}`, currentX, yPos);
    currentX += colWidths[3];
    doc.text(attempt.skipped ? 'Ja' : 'Nee', currentX, yPos);

    yPos += 7;
  });

  // Save PDF
  const dateStr = new Date().toISOString().split('T')[0];
  doc.save(`TypeTrainer_${student.studentNumber}_${dateStr}.pdf`);
};

import React, { useState } from 'react';
import { Student } from '../types';

interface LoginProps {
  onStart: (student: Student) => void;
}

const Login: React.FC<LoginProps> = ({ onStart }) => {
  const [name, setName] = useState('');
  const [studentNumber, setStudentNumber] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (name.trim() && studentNumber.trim()) {
      onStart({ name, studentNumber });
    }
  };

  return (
    <div className="flex flex-col items-center justify-center h-full bg-blue-50">
      <div className="bg-white p-8 rounded-xl shadow-lg w-full max-w-md">
        <h1 className="text-3xl font-bold mb-6 text-center text-blue-700">Type Trainer</h1>
        <p className="text-gray-600 mb-8 text-center">Voer je gegevens in om te beginnen.</p>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Volledige Naam</label>
            <input
              type="text"
              required
              className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="bijv. Jan de Vries"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Studentnummer</label>
            <input
              type="text"
              required
              className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
              value={studentNumber}
              onChange={(e) => setStudentNumber(e.target.value)}
              placeholder="bijv. 123456"
            />
          </div>
          <button
            type="submit"
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-lg transition-colors shadow-md mt-4"
          >
            Start Training
          </button>
        </form>
      </div>
    </div>
  );
};

export default Login;

import React, { useEffect } from 'react';
import { Task } from '../types';

interface HelpOverlayProps {
  onClose: () => void;
  currentTarget?: Task;
}

const HelpOverlay: React.FC<HelpOverlayProps> = ({ onClose, currentTarget }) => {
  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [onClose]);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-3xl max-h-[90vh] flex flex-col">
        <div className="p-6 border-b flex justify-between items-center bg-gray-50 rounded-t-2xl">
          <h2 className="text-2xl font-bold text-gray-800">Uitleg & QWERTY Hulp</h2>
          <button 
            onClick={onClose}
            className="text-gray-500 hover:text-gray-800 text-2xl font-bold p-2"
          >
            ×
          </button>
        </div>

        <div className="p-8 overflow-y-auto space-y-8 flex-1">
          <section>
            <h3 className="text-xl font-semibold mb-3 text-blue-700">Instructies</h3>
            <p className="text-gray-700 leading-relaxed">
              Typ exact hetzelfde teken als getoond in het linker vak.
              Gebruik <strong>Shift</strong> voor hoofdletters en speciale tekens.
              Let goed op de <strong>Caps Lock</strong> status.
            </p>
          </section>

          {currentTarget && (
            <section className="bg-blue-50 p-4 rounded-lg border border-blue-100">
              <h3 className="text-lg font-semibold mb-2 text-blue-800">Huidige Opdracht</h3>
              <p className="text-gray-800">
                Teken: <span className="text-2xl font-mono font-bold mx-2">'{currentTarget.character}'</span>
                <br />
                <span className="italic text-gray-600">Tip: {currentTarget.hint}</span>
              </p>
            </section>
          )}

          <section>
            <h3 className="text-xl font-semibold mb-4 text-blue-700">QWERTY Mapping</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-2 font-mono text-sm bg-gray-50 p-4 rounded-lg border">
              <div>Shift + 1..9 → ! @ # $ % ^ & * (</div>
              <div>[ en ] → [ ]</div>
              <div>Shift + [ → {"{"}</div>
              <div>Shift + ] → {"}"}</div>
              <div>; → ;</div>
              <div>Shift + ; → :</div>
              <div>' → '</div>
              <div>Shift + ' → "</div>
              <div>\ → \</div>
              <div>Shift + \ → |</div>
              <div>, → ,</div>
              <div>Shift + , → &lt;</div>
              <div>. → .</div>
              <div>Shift + . → &gt;</div>
              <div>/ → /</div>
              <div>Shift + / → ?</div>
              <div>` → `</div>
              <div>Shift + ` → ~</div>
              <div>- → -</div>
              <div>Shift + - → _</div>
              <div>= → =</div>
              <div>Shift + = → +</div>
            </div>
          </section>
        </div>

        <div className="p-6 border-t flex justify-end">
          <button
            onClick={onClose}
            className="px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-lg transition-colors"
          >
            Sluiten
          </button>
        </div>
      </div>
    </div>
  );
};

export default HelpOverlay;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Student, GameState, Task, TaskAttempt, SessionSummary } from './types';
import { generateTasks } from './game/generator';
import Login from './components/Login';
import HelpOverlay from './components/HelpOverlay';
import ResultsScreen from './components/ResultsScreen';

const App: React.FC = () => {
  // Global State
  const [student, setStudent] = useState<Student | null>(null);
  const [gameState, setGameState] = useState<GameState>(GameState.LOGIN);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [attempts, setAttempts] = useState<TaskAttempt[]>([]);
  const [summary, setSummary] = useState<SessionSummary | null>(null);

  // UI State
  const [userInput, setUserInput] = useState('');
  const [feedback, setFeedback] = useState<{ text: string; type: 'success' | 'error' | 'neutral' }>({ text: '', type: 'neutral' });
  const [isHelpOpen, setIsHelpOpen] = useState(false);
  const [capsLockActive, setCapsLockActive] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);

  // Initialize Game
  const startSession = (s: Student) => {
    const newTasks = generateTasks();
    setStudent(s);
    setTasks(newTasks);
    setCurrentIndex(0);
    setAttempts([]);
    setUserInput('');
    setFeedback({ text: 'Typ het teken om te beginnen.', type: 'neutral' });
    setGameState(GameState.PLAYING);
    setSummary({
      startTimestampISO: new Date().toISOString(),
      endTimestampISO: '',
      totalErrors: 0,
      totalSkipped: 0,
      correctOnFirstTryCount: 0,
      totalAttempts: 0
    });
  };

  const handleLogout = () => {
    setStudent(null);
    setGameState(GameState.LOGIN);
    setTasks([]);
    setAttempts([]);
  };

  const currentTaskAttempt = useRef<{
    attempts: number;
    errors: number;
    history: string[];
    isFirstTry: boolean;
  }>({ attempts: 0, errors: 0, history: [], isFirstTry: true });

  const nextTask = useCallback((skipped = false) => {
    const target = tasks[currentIndex].character;
    const finalAttempt: TaskAttempt = {
      index: currentIndex + 1,
      target: target,
      firstTryCorrect: skipped ? false : currentTaskAttempt.current.isFirstTry,
      attempts: currentTaskAttempt.current.attempts + (skipped ? 0 : 0), // Already updated in handleInput
      errors: currentTaskAttempt.current.errors,
      skipped: skipped,
      typedHistory: currentTaskAttempt.current.history.slice(-3)
    };

    setAttempts(prev => [...prev, finalAttempt]);

    // Update summary counters
    setSummary(prev => {
      if (!prev) return null;
      return {
        ...prev,
        totalErrors: prev.totalErrors + currentTaskAttempt.current.errors,
        totalSkipped: prev.totalSkipped + (skipped ? 1 : 0),
        correctOnFirstTryCount: prev.correctOnFirstTryCount + (finalAttempt.firstTryCorrect && !skipped ? 1 : 0),
        totalAttempts: prev.totalAttempts + currentTaskAttempt.current.attempts
      };
    });

    // Reset attempt tracker
    currentTaskAttempt.current = { attempts: 0, errors: 0, history: [], isFirstTry: true };

    if (currentIndex < 29) {
      setCurrentIndex(prev => prev + 1);
      setUserInput('');
      setFeedback({ text: 'Typ het volgende teken.', type: 'neutral' });
      setIsProcessing(false);
    } else {
      // Game End
      setSummary(prev => {
        if (!prev) return null;
        return { ...prev, endTimestampISO: new Date().toISOString() };
      });
      setGameState(GameState.RESULTS);
    }
  }, [currentIndex, tasks]);

  const handleInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (isProcessing) return;
    const val = e.target.value;
    if (!val) return;

    setUserInput(val);
    const char = val.slice(-1);
    const target = tasks[currentIndex].character;

    currentTaskAttempt.current.attempts++;
    currentTaskAttempt.current.history.push(char);

    if (char === target) {
      setFeedback({ text: 'Correct!', type: 'success' });
      setIsProcessing(true);
      setTimeout(() => {
        nextTask(false);
      }, 350);
    } else {
      setFeedback({ text: 'Niet correct, probeer opnieuw.', type: 'error' });
      currentTaskAttempt.current.errors++;
      currentTaskAttempt.current.isFirstTry = false;
      setIsProcessing(true);
      setTimeout(() => {
        setUserInput('');
        setIsProcessing(false);
        inputRef.current?.focus();
      }, 400);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    setCapsLockActive(e.getModifierState("CapsLock"));
  };

  useEffect(() => {
    if (gameState === GameState.PLAYING && inputRef.current) {
      inputRef.current.focus();
    }
  }, [gameState, currentIndex, isProcessing]);

  if (gameState === GameState.LOGIN) {
    return <Login onStart={startSession} />;
  }

  if (gameState === GameState.RESULTS && student && summary) {
    return (
      <ResultsScreen 
        student={student} 
        summary={summary} 
        attempts={attempts} 
        onReset={handleLogout} 
      />
    );
  }

  return (
    <div className="h-screen w-screen flex flex-col bg-slate-100 select-none overflow-hidden" onKeyDown={handleKeyDown}>
      {/* Header */}
      <header className="h-16 bg-white border-b px-6 flex items-center justify-between shrink-0 shadow-sm z-10">
        <div className="flex items-center gap-4">
          <h1 className="text-xl font-bold text-blue-800">Type Trainer</h1>
          <div className="h-6 w-px bg-gray-200" />
          <p className="text-gray-600 font-medium">
            {student?.name} — <span className="text-gray-400">{student?.studentNumber}</span>
          </p>
        </div>
        <div className="flex gap-3">
          <button
            onClick={() => setIsHelpOpen(true)}
            className="px-4 py-2 bg-blue-50 text-blue-700 font-bold rounded-lg hover:bg-blue-100 transition-colors border border-blue-200"
          >
            Hulp / Hint
          </button>
          <button
            onClick={handleLogout}
            className="px-4 py-2 bg-gray-100 text-gray-600 font-bold rounded-lg hover:bg-gray-200 transition-colors"
          >
            Afmelden
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 flex flex-col items-center justify-center p-8 gap-12 relative">

        {/* Progress Bar */}
        <div className="absolute top-8 w-full max-w-2xl px-8">
          <div className="flex justify-between text-xs font-bold text-gray-400 mb-2 uppercase tracking-widest">
            <span>Voortgang</span>
            <span>Opdracht {currentIndex + 1} / 30</span>
          </div>
          <div className="h-2 w-full bg-gray-200 rounded-full overflow-hidden">
            <div 
              className="h-full bg-blue-500 transition-all duration-500"
              style={{ width: `${((currentIndex + 1) / 30) * 100}%` }}
            />
          </div>
        </div>

        {/* Typing Area */}
        <div className="flex items-center gap-12">
          {/* Target Card */}
          <div className="flex flex-col items-center">
             <div className="text-sm font-bold text-gray-400 mb-3 uppercase tracking-wider">Doel</div>
             <div className="w-64 h-64 bg-white rounded-3xl shadow-xl border-4 border-blue-100 flex items-center justify-center">
                <span className="text-9xl font-mono font-bold text-blue-800">
                  {tasks[currentIndex]?.character}
                </span>
             </div>
          </div>

          <div className="text-4xl text-gray-300 font-light">→</div>

          {/* Input Card */}
          <div className="flex flex-col items-center">
             <div className="text-sm font-bold text-gray-400 mb-3 uppercase tracking-wider">Jouw Invoer</div>
             <div className={`w-64 h-64 bg-white rounded-3xl shadow-xl border-4 transition-colors flex items-center justify-center relative ${
               feedback.type === 'success' ? 'border-green-400 bg-green-50' : 
               feedback.type === 'error' ? 'border-red-400 bg-red-50' : 'border-gray-100'
             }`}>
                <input
                  ref={inputRef}
                  type="text"
                  maxLength={1}
                  value={userInput}
                  onChange={handleInput}
                  disabled={isProcessing}
                  onKeyDown={handleKeyDown}
                  className="w-full h-full bg-transparent text-center text-9xl font-mono font-bold text-gray-800 focus:outline-none"
                />

                {/* Caps Lock Indicator */}
                {capsLockActive && (
                  <div className="absolute bottom-4 bg-orange-500 text-white text-[10px] px-2 py-1 rounded font-bold uppercase animate-pulse">
                    Caps Lock Aan
                  </div>
                )}
             </div>
          </div>
        </div>

        {/* Feedback and Control Area */}
        <div className="flex flex-col items-center gap-6 w-full max-w-md">
           <div className={`text-xl font-bold px-8 py-3 rounded-full transition-all text-center min-h-[56px] flex items-center ${
             feedback.type === 'success' ? 'text-green-600 bg-green-100' : 
             feedback.type === 'error' ? 'text-red-600 bg-red-100' : 'text-gray-500 bg-gray-200'
           }`}>
             {feedback.text}
           </div>

           <button
             onClick={() => nextTask(true)}
             className="text-gray-400 hover:text-blue-600 font-bold transition-colors underline underline-offset-4"
           >
             Deze opdracht overslaan
           </button>
        </div>
      </main>

      {/* Overlays */}
      {isHelpOpen && (
        <HelpOverlay 
          onClose={() => setIsHelpOpen(false)} 
          currentTarget={tasks[currentIndex]} 
        />
      )}
    </div>
  );
};

export default App;

import { Task } from '../types';

const LETTERS = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ".split("");
const NUMBERS = "0123456789".split("");
const SHIFT_SYMBOLS = "!@#$%^&*(".split("");
// Characters removed: ' " `
const PUNCTUATION = "{[]};:\\|,. < >/?~_-+=".split("").filter(c => c !== " ");

const getHint = (char: string): string => {
  if (/[a-z]/.test(char)) return "Kleine letter.";
  if (/[A-Z]/.test(char)) return "Grote letter (gebruik Shift).";
  if (/[0-9]/.test(char)) return "Cijfer.";
  if (SHIFT_SYMBOLS.includes(char)) return `Gebruik Shift en de ${"123456789".charAt(SHIFT_SYMBOLS.indexOf(char))}`;

  const mappings: Record<string, string> = {
    '[': 'Het haakje links.',
    ']': 'Het haakje rechts.',
    '{': 'Shift en [',
    '}': 'Shift en ]',
    ';': 'De puntkomma.',
    ':': 'Shift en ;',
    '\\': 'De schuine streep naar links.',
    '|': 'Shift en \\',
    ',': 'De komma.',
    '<': 'Shift en ,',
    '.': 'De punt.',
    '>': 'Shift en .',
    '/': 'De schuine streep naar rechts.',
    '?': 'Shift en /',
    '~': 'Shift en de toets links van de 1.',
    '-': 'Het streepje.',
    '_': 'Shift en -',
    '=': 'Is-gelijk teken.',
    '+': 'Shift en ='
  };

  return mappings[char] || "Speciaal teken.";
};

export const generateTasks = (): Task[] => {
  const tasks: Task[] = [];
  const charCounts: Record<string, number> = {};

  const getRandomFrom = (pool: string[]): string => {
    let char = pool[Math.floor(Math.random() * pool.length)];
    let safety = 0;
    // Max 2 entries per session to keep it varied
    while (charCounts[char] >= 2 && safety < 100) {
      char = pool[Math.floor(Math.random() * pool.length)];
      safety++;
    }
    charCounts[char] = (charCounts[char] || 0) + 1;
    return char;
  };

  // 1-5: Letters only (as per original flow, but now for 50 total)
  for (let i = 0; i < 5; i++) {
    const char = getRandomFrom(LETTERS);
    tasks.push({ character: char, hint: getHint(char) });
  }

  // 6-50: Mixed
  const mixedPool = [...LETTERS, ...NUMBERS, ...SHIFT_SYMBOLS, ...PUNCTUATION];
  for (let i = 5; i < 50; i++) {
    const char = getRandomFrom(mixedPool);
    tasks.push({ character: char, hint: getHint(char) });
  }

  return tasks;
};

