        </div>

        {/* Feedback and Control Area */}
        <div className="flex flex-col items-center gap-6 w-full max-w-md">
           <div className={`text-xl font-bold px-8 py-3 rounded-full transition-all text-center min-h-[56px] flex items-center ${
             feedback.type === 'success' ? 'text-green-600 bg-green-100' : 
             feedback.type === 'error' ? 'text-red-600 bg-red-100' : 'text-gray-500 bg-gray-200'
           }`}>
             {feedback.text}
           </div>

           <button
             onClick={() => nextTask(true)}
             className="text-gray-400 hover:text-blue-600 font-bold transition-colors underline underline-offset-4"
           >
             Vraag overslaan
           </button>
        </div>
      </main>

      {/* Overlays */}
      {isHelpOpen && (
        <HelpOverlay 
          onClose={() => setIsHelpOpen(false)} 
          currentTarget={tasks[currentIndex]} 
        />
      )}
    </div>
